// Validation with Proxy
const validator = {
  set(target, prop, value) {
    if (prop === 'age') {
      if (typeof value !== 'number' || value < 0 || value > 150) {
        throw new RangeError('Age must be a number between 0 and 150');
      }
    }
    return Reflect.set(target, prop, value); // default behaviour
  }
};

const person = new Proxy({}, validator);
person.name = 'Alice'; // ✅
person.age = 30;       // ✅
// person.age = -5;    // ❌ RangeError

// Logging proxy
function createLoggedObject(target) {
  return new Proxy(target, {
    get(obj, prop) {
      console.log(`GET: ${String(prop)}`);
      return Reflect.get(obj, prop);
    }
  });
}
const logged = createLoggedObject({ x: 10 });
console.log(logged.x); // logs 'GET: x' then 10
